import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
import type { BaseProbeResult } from "openclaw/plugin-sdk/channel-contract";
import type { DmPolicy, GroupPolicy } from "openclaw/plugin-sdk/setup";
import type { z } from "openclaw/plugin-sdk/zod";
import type { ToolPolicySchema } from "openclaw/plugin-sdk/channel-config-schema";

export type GroupToolPolicyConfig = z.infer<typeof ToolPolicySchema>;

export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiUrl?: string;
  token?: string;
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: Record<string, PulseBoardGroupConfig>;
  textChunkLimit?: number;
  blockStreaming?: boolean;
};

/** Single-account config (PulseBoard does not support multi-account). */
export type PulseBoardConfig = PulseBoardAccountConfig;

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  username: string;
  latencyMs?: number;
};

