import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  apiUrl: string;
  username: string;
  config: PulseBoardAccountConfig;
};

const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });
export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(params.accountId);
  const section = params.cfg.channels?.pulseboard;
  const baseEnabled = section?.enabled !== false;

  const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;

  const apiUrl = (
    section?.apiUrl?.trim() ||
    (isDefaultAccount ? process.env.PULSEBOARD_API_URL?.trim() : "") ||
    ""
  ).trim();

  const token = (
    section?.token?.trim() ||
    (isDefaultAccount ? process.env.PULSEBOARD_TOKEN?.trim() : "") ||
    ""
  ).trim();

  const username = (
    section?.username?.trim() ||
    (isDefaultAccount ? process.env.PULSEBOARD_USERNAME?.trim() : "") ||
    "openclaw"
  ).trim();

  const config: PulseBoardAccountConfig = {
    ...section,
    apiUrl: apiUrl || undefined,
    token: token || undefined,
    username: username || undefined,
  };

  return {
    accountId,
    enabled: baseEnabled,
    name: section?.name?.trim() || undefined,
    configured: Boolean(apiUrl && token),
    apiUrl,
    username,
    config,
  };
}

