import type { PulseBoardInboundMessage } from "./types.js";

const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/** Returns true when the target is a board (prefixed with ~). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("~");
}

/**
 * Normalize a raw messaging target string into a canonical PulseBoard target.
 * Strips the `pulseboard:` channel prefix, resolves `board:`/`user:` kind
 * prefixes, and ensures boards start with `~`.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  const lowered = target.toLowerCase();

  // Strip channel prefix
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Handle kind prefixes
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("~")) {
      target = `~${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
    // Strip leading @ for user targets (normalized form is without @)
    if (target.startsWith("@")) {
      target = target.slice(1);
    }
  }

  // Strip leading @ for bare user targets as well
  if (target.startsWith("@")) {
    target = target.slice(1);
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true if the string looks like a plausible PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/** Normalize an allowlist entry: lowercase, strip prefixes and leading @. */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

export function buildPulseBoardAllowlistCandidates(message: PulseBoardInboundMessage): string[] {
  const username = message.senderUsername.trim().toLowerCase();
  if (!username) {
    return [];
  }
  return [username];
}

export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseBoardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseBoardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowFrom.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

/**
 * Simple text chunker that splits on newline or space boundaries.
 * PulseBoard has a 4000-character limit per message.
 */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (text.length <= limit) {
    return [text];
  }
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= limit) {
      chunks.push(remaining);
      break;
    }
    const window = remaining.slice(0, limit);
    const lastNewline = window.lastIndexOf("\n");
    const lastSpace = window.lastIndexOf(" ");
    const breakAt = lastNewline > 0 ? lastNewline : lastSpace > 0 ? lastSpace : limit;
    chunks.push(remaining.slice(0, breakAt));
    remaining = remaining.slice(breakAt).replace(/^[\n ]/, "");
  }
  return chunks;
}

