      username: (setupInput.username as string | undefined)?.trim(),
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};

/** Normalize a board entry: ensure it starts with ~ unless it is the wildcard. */
export function normalizeBoardEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  const stripped = trimmed.replace(/^~+/, "");
  if (!stripped) {
    return null;
  }
  return `~${stripped}`;
}

