import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
  formatDocsLink,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import {
  normalizeBoardEntry,
  pulseBoardSetupAdapter,
  setPulseBoardAllowFrom,
  setPulseBoardDmPolicy,
  setPulseBoardGroupAccess,
  updatePulseBoardConfig,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;
const USE_ENV_FLAG = "__pulseBoardUseEnv";

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

const pulseBoardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseBoardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) => {
    const current = (cfg as CoreConfig).channels?.pulseboard?.allowFrom ?? [];
    const raw = String(
      await prompter.text({
        message: "PulseBoard allowFrom (username, comma-separated)",
        initialValue: current.map(String).join(", "),
        validate: () => undefined,
      }),
    );
    const entries = parseListInput(raw)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean);
    return setPulseBoardAllowFrom(cfg as CoreConfig, entries);
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API URL + token",
    configuredHint: "configured",
    unconfiguredHint: "needs API URL + token",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs an API URL and API token.",
      "Optionally set a bot username (defaults to openclaw).",
      "Env vars supported: PULSEBOARD_API_URL, PULSEBOARD_TOKEN, PULSEBOARD_USERNAME.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues }) => {
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envApiUrl = isDefaultAccount ? process.env.PULSEBOARD_API_URL?.trim() : "";
    const envToken = isDefaultAccount ? process.env.PULSEBOARD_TOKEN?.trim() : "";
    const envReady = Boolean(
      envApiUrl && envToken && !resolved.config.apiUrl && !resolved.config.token,
    );

    if (envReady) {
      return {
        cfg: updatePulseBoardConfig(cfg as CoreConfig, { enabled: true }),
        credentialValues: {
          ...credentialValues,
          [USE_ENV_FLAG]: "1",
        },
      };
    }

    return {
      cfg: updatePulseBoardConfig(cfg as CoreConfig, { enabled: true }),
      credentialValues: {
        ...credentialValues,
        [USE_ENV_FLAG]: "0",
      },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL",
      placeholder: "https://api.pulseboard.example",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiUrl || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, value }) =>
        updatePulseBoardConfig(cfg as CoreConfig, {
          enabled: true,
          apiUrl: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard API token",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.token
          ? "(set)"
          : undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, value }) =>
        updatePulseBoardConfig(cfg as CoreConfig, {
          enabled: true,
          token: value,
        }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard username",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username ||
        undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      initialValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username ||
        "openclaw",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, value }) =>
        updatePulseBoardConfig(cfg as CoreConfig, {
          enabled: true,
          username: value,
        }),
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "~general, ~announcements, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ??
      "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards ?? {},
      ),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards,
      ),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseBoardGroupAccess(cfg as CoreConfig, policy, [], normalizeBoardEntry),
    resolveAllowlist: async ({ entries }) =>
      [...new Set(entries.map((entry) => normalizeBoardEntry(entry)).filter(Boolean))] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseBoardGroupAccess(
        cfg as CoreConfig,
        "allowlist",
        resolved as string[],
        normalizeBoardEntry,
      ),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender.",
      "Examples:",
      "- alice",
      "- @bob",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (username)",
    placeholder: "alice, bob",
    invalidWithoutCredentialNote: "Use a PulseBoard username.",
    parseId: (raw) => {
      const normalized = normalizePulseBoardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) =>
      setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };

