import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  normalizePulseBoardMessagingTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  buildPulseBoardAllowlistCandidates,
  resolvePulseBoardAllowlistMatch,
  chunkTextForOutbound,
} from "./normalize.js";

describe("pulseboard normalize", () => {
  describe("isBoardTarget", () => {
    it("returns true for targets with ~ prefix", () => {
      expect(isBoardTarget("~general")).toBe(true);
      expect(isBoardTarget("~announcements")).toBe(true);
    });

    it("returns false for user targets", () => {
      expect(isBoardTarget("alice")).toBe(false);
      expect(isBoardTarget("@bob")).toBe(false);
    });
  });

  describe("normalizePulseBoardMessagingTarget", () => {
    it("strips pulseboard: channel prefix", () => {
      expect(normalizePulseBoardMessagingTarget("pulseboard:alice")).toBe("alice");
      expect(normalizePulseBoardMessagingTarget("PulseBoard:~general")).toBe("~general");
    });

    it("handles board: kind prefix", () => {
      expect(normalizePulseBoardMessagingTarget("board:general")).toBe("~general");
      expect(normalizePulseBoardMessagingTarget("board:~general")).toBe("~general");
    });

    it("handles user: kind prefix", () => {
      expect(normalizePulseBoardMessagingTarget("user:alice")).toBe("alice");
      expect(normalizePulseBoardMessagingTarget("user:@alice")).toBe("alice");
    });

    it("strips leading @ from bare user targets", () => {
      expect(normalizePulseBoardMessagingTarget("@alice")).toBe("alice");
    });

    it("returns undefined for empty or whitespace input", () => {
      expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
      expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
      expect(normalizePulseBoardMessagingTarget("\n")).toBeUndefined();
    });

    it("preserves board prefix", () => {
      expect(normalizePulseBoardMessagingTarget("~general")).toBe("~general");
    });
  });

  describe("looksLikePulseBoardTargetId", () => {
    it("accepts valid target ids", () => {
      expect(looksLikePulseBoardTargetId("alice")).toBe(true);
      expect(looksLikePulseBoardTargetId("~general")).toBe(true);
    });

    it("rejects empty and whitespace", () => {
      expect(looksLikePulseBoardTargetId("")).toBe(false);
      expect(looksLikePulseBoardTargetId("   ")).toBe(false);
    });

    it("rejects strings with whitespace", () => {
      expect(looksLikePulseBoardTargetId("alice bob")).toBe(false);
    });
  });

  describe("normalizePulseBoardAllowEntry", () => {
    it("lowercases and strips prefixes", () => {
      expect(normalizePulseBoardAllowEntry("PulseBoard:User:Alice")).toBe("alice");
      expect(normalizePulseBoardAllowEntry("@Bob")).toBe("bob");
      expect(normalizePulseBoardAllowEntry("user:@Charlie")).toBe("charlie");
    });

    it("returns empty string for empty input", () => {
      expect(normalizePulseBoardAllowEntry("")).toBe("");
      expect(normalizePulseBoardAllowEntry("   ")).toBe("");
    });
  });

  describe("normalizePulseBoardAllowlist", () => {
    it("normalizes an array of entries", () => {
      expect(normalizePulseBoardAllowlist(["Alice", "@Bob", 42])).toEqual([
        "alice",
        "bob",
        "42",
      ]);
    });

    it("handles undefined", () => {
      expect(normalizePulseBoardAllowlist(undefined)).toEqual([]);
    });
  });

  describe("allowlist matching", () => {
    const message = {
      messageId: "m1",
      target: "alice",
      senderUsername: "Alice",
      text: "hello",
      timestamp: Date.now(),
      isGroup: false,
    };

    it("builds candidates from sender username", () => {
      expect(buildPulseBoardAllowlistCandidates(message)).toEqual(["alice"]);
    });

    it("matches sender against allowlist", () => {
      expect(
        resolvePulseBoardAllowlistMatch({
          allowFrom: ["alice"],
          message,
        }).allowed,
      ).toBe(true);
    });

    it("matches wildcard", () => {
      const result = resolvePulseBoardAllowlistMatch({
        allowFrom: ["*"],
        message,
      });
      expect(result.allowed).toBe(true);
      expect(result.source).toBe("wildcard");
    });

    it("rejects non-matching sender", () => {
      expect(
        resolvePulseBoardAllowlistMatch({
          allowFrom: ["bob"],
          message,
        }).allowed,
      ).toBe(false);
    });
  });
});

describe("chunkTextForOutbound", () => {
  it("returns single chunk for short text", () => {
    expect(chunkTextForOutbound("hello", 4000)).toEqual(["hello"]);
  });

  it("splits long text on newline boundaries", () => {
    const line = "a".repeat(50);
    const text = `${line}\n${line}\n${line}`;
    const chunks = chunkTextForOutbound(text, 55);
    expect(chunks.length).toBeGreaterThan(1);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(55);
    }
  });

  it("splits long text on space boundaries when no newlines", () => {
    const text = Array.from({ length: 20 }, () => "word").join(" ");
    const chunks = chunkTextForOutbound(text, 30);
    expect(chunks.length).toBeGreaterThan(1);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(30);
    }
  });

  it("handles text with no break points", () => {
    const text = "a".repeat(100);
    const chunks = chunkTextForOutbound(text, 40);
    expect(chunks.length).toBe(3);
    expect(chunks[0]).toBe("a".repeat(40));
  });
});

