import { describe, expect, it } from "vitest";
import { PulseBoardConfigSchema } from "./config-schema.js";

describe("pulseboard config schema", () => {
  it("accepts valid config with apiUrl and token", () => {
    const parsed = PulseBoardConfigSchema.parse({
      apiUrl: "https://api.pulseboard.example",
      token: "pb-secret-token",
      username: "openclaw-bot",
    });

    expect(parsed.apiUrl).toBe("https://api.pulseboard.example");
    expect(parsed.token).toBe("pb-secret-token");
    expect(parsed.username).toBe("openclaw-bot");
  });

  it("applies default dmPolicy and groupPolicy", () => {
    const parsed = PulseBoardConfigSchema.parse({});
    expect(parsed.dmPolicy).toBe("pairing");
    expect(parsed.groupPolicy).toBe("allowlist");
    expect(parsed.textChunkLimit).toBe(4000);
  });

  it("accepts numeric allowFrom entries", () => {
    const parsed = PulseBoardConfigSchema.parse({
      dmPolicy: "allowlist",
      allowFrom: [12345, "alice"],
    });

    expect(parsed.allowFrom).toEqual([12345, "alice"]);
  });

  it("accepts per-board allowFrom entries in boards", () => {
    const parsed = PulseBoardConfigSchema.parse({
      boards: {
        "~ops": {
          allowFrom: [42, "alice"],
        },
      },
    });

    expect(parsed.boards?.["~ops"]?.allowFrom).toEqual([42, "alice"]);
  });

  it("rejects dmPolicy open without wildcard allowFrom", () => {
    expect(() =>
      PulseBoardConfigSchema.parse({
        dmPolicy: "open",
        allowFrom: ["alice"],
      }),
    ).toThrow();
  });

  it("accepts dmPolicy open with wildcard allowFrom", () => {
    const parsed = PulseBoardConfigSchema.parse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });

    expect(parsed.dmPolicy).toBe("open");
  });
});

