  it("returns default when no config exists", () => {
    expect(listPulseBoardAccountIds(asConfig({}))).toEqual(["default"]);
  });

  it("returns default when pulseboard config exists", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://api.pulseboard.example",
          token: "tok",
        },
      },
    });
    expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves from config", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://api.pulseboard.example",
          token: "my-token",
          username: "bot-user",
        },
      },
    });

    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.apiUrl).toBe("https://api.pulseboard.example");
    expect(account.username).toBe("bot-user");
  });

  it("resolves from environment variables", () => {
    vi.stubEnv("PULSEBOARD_API_URL", "https://env.pulseboard.example");
