    expect(account.apiUrl).toBe("https://env.pulseboard.example");
    expect(account.username).toBe("env-user");
  });

  it("marks as not configured when apiUrl is missing", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          token: "my-token",
        },
      },
