    const cfg = asConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://api.pulseboard.example",
        },
      },
    });

    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("defaults username to openclaw when not set", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://api.pulseboard.example",
          token: "tok",
        },
      },
    });

    const account = resolvePulseBoardAccount({ cfg });
    expect(account.username).toBe("openclaw");
  });

  it("respects enabled flag", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          enabled: false,
          apiUrl: "https://api.pulseboard.example",
          token: "tok",
        },
      },
    });

    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(false);
    expect(account.configured).toBe(true);
  });
});

